const { sql } = require('slonik');

function solve({ tags, difficulty, limit }) {
  // Normalize and parse tags filter
  let normalizedTags = [];
  if (tags) {
    if (Array.isArray(tags)) {
      normalizedTags = tags.flatMap(t => t.split(',')).map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
    } else if (typeof tags === 'string') {
      normalizedTags = tags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
    }
  }

  // Compose SQL filters
  const filters = [];
  const values = [];

  if (difficulty) {
    filters.push(sql`difficulty = ${difficulty}`);
  }

  if (normalizedTags.length > 0) {
    // Filter problems that have any of the tags (case-insensitive)
    filters.push(sql`EXISTS (
      SELECT 1 FROM problem_tags pt
      WHERE pt.problem_id = problems.id
      AND LOWER(pt.tag) = ANY(${normalizedTags})
    )`);
  }

  // Compose WHERE clause
  const whereClause = filters.length > 0 ? sql`WHERE ${sql.join(filters, sql` AND `)}` : sql``;

  // Compose query with stable ordering and limit
  const query = sql`
    SELECT problems.*, 
      ARRAY(
        SELECT DISTINCT LOWER(tag) FROM problem_tags pt WHERE pt.problem_id = problems.id ORDER BY LOWER(tag)
      ) AS normalized_tags
    FROM problems
    ${whereClause}
    ORDER BY problems.difficulty ASC, problems.id ASC
    LIMIT ${limit || 50}
  `;

  // Return query and metadata with appliedTags
  return {
    query,
    metadata: {
      appliedTags: normalizedTags.length > 0 ? normalizedTags : null,
      difficulty: difficulty || null,
      limit: limit || 50,
    },
  };
}

module.exports = { solve };
